parameters.jsCode:
const report = $json;
const orders = report.orders || [];

let csv = 'Order Code,Customer Name,Total Amount (VND),Status,Region,Created At\n';

for (const row of orders) {
  csv += `${row.order_code || ''},${row.customer_name || ''},${row.total_amount || 0},${row.status || ''},${row.region || ''},${row.created_at || ''}\n`;
}

const totalOrders = Number(report.total_orders || 0);
const totalRevenue = Number(report.total_revenue || 0);

const formattedRevenue = totalRevenue.toLocaleString('vi-VN');

const emailHTML = `
<div style="font-family: Arial, sans-serif; max-width:600px; margin:auto; border:1px solid #ddd; border-radius:10px; padding:20px;">
  <h2 style="color:#1f2937;">${report.email_subject}</h2>

  <p><b>Ngày báo cáo:</b> ${new Date().toLocaleDateString('vi-VN')}</p>

  <div style="background:#f3f4f6; padding:15px; border-radius:8px; margin:15px 0;">
    <p>🧾 <b>Tổng đơn:</b> ${totalOrders}</p>
    <p>💰 <b>Doanh thu:</b> ${formattedRevenue} VND</p>
  </div>

  <p>📎 File CSV được đính kèm.</p>

  <hr/>

  <p style="color:gray; font-size:12px;">
    ⚙️ Generated automatically by <b>DashAuto Automation System</b>
  </p>
</div>
`;

return [
  {
    json: {
      ...report,
      email_body: emailHTML,
      report_content: `Tong don: ${totalOrders} | Doanh thu: ${formattedRevenue} VND`,
      email_status: 'success',
    },

    binary: {
      data: {
        data: Buffer.from(csv).toString('base64'),
        mimeType: 'text/csv',
        fileName: `${report.file_prefix}_${new Date().toISOString().slice(0, 10)}.csv`,
      },
    },
  },
];

const config = $('update daily report').item.json;
const today = new Date().toLocaleDateString('vi-VN');

let titleText = '⚠️ SALES REPORT - NO ORDERS';
if (config.report_type === 'daily') titleText = '⚠️ DAILY REPORT - NO ORDERS';
if (config.report_type === 'weekly') titleText = '⚠️ WEEKLY REPORT - NO ORDERS';
if (config.report_type === 'monthly') titleText = '⚠️ MONTHLY REPORT - NO ORDERS';

const emailHTML = `
<div style="font-family: Arial, sans-serif; max-width:600px; margin:auto; border:1px solid #ddd; border-radius:10px; padding:20px;">
  <h2 style="color:#92400e;">${titleText}</h2>
  <p><b>Ngày báo cáo:</b> ${today}</p>

  <div style="background:#fff7ed; padding:15px; border-radius:8px; margin:15px 0;">
    <p>🧾 <b>Tổng đơn:</b> 0</p>
    <p>💰 <b>Doanh thu:</b> 0 VND</p>
    <p>📌 <b>Trạng thái:</b> Không có đơn hàng trong kỳ báo cáo.</p>
  </div>

  <p>Hệ thống vẫn ghi nhận báo cáo để quản lý biết workflow đã chạy thành công.</p>
</div>
`;

return [
  {
    json: {
      total_orders: 0,
      total_revenue: 0,
      email_subject: `${config.email_subject} - No Orders`,
      email_body: emailHTML,
      report_title: `${config.report_title} - Khong co don`,
      report_type: `${config.report_type}_no_data`,
      report_content: 'Khong co don hang | Tong don: 0 | Doanh thu: 0 VND',
      email_status: 'success',
    },
  },
];

const now = new Date();

const dayOfWeek = now.getDay(); // 0 CN, 1 T2
const dayOfMonth = now.getDate();

let reportType = 'daily';
let title = 'Bao cao tu dong hang ngay';
let subject = '📊 Daily Sales Report - DashAuto';
let filePrefix = 'daily_report';

let startSql = "date_trunc('day', NOW()) - INTERVAL '1 day'";
let endSql = "date_trunc('day', NOW())";

if (dayOfMonth === 1) {
  reportType = 'monthly';
  title = 'Bao cao tu dong hang thang';
  subject = '📊 Monthly Sales Report - DashAuto';
  filePrefix = 'monthly_report';
  startSql = "date_trunc('month', NOW()) - INTERVAL '1 month'";
  endSql = "date_trunc('month', NOW())";
} else if (dayOfWeek === 1) {
  reportType = 'weekly';
  title = 'Bao cao tu dong hang tuan';
  subject = '📊 Weekly Sales Report - DashAuto';
  filePrefix = 'weekly_report';
  startSql = "date_trunc('week', NOW()) - INTERVAL '1 week'";
  endSql = "date_trunc('week', NOW())";
}

return [
  {
    json: {
      report_type: reportType,
      report_title: title,
      email_subject: subject,
      file_prefix: filePrefix,
      start_sql: startSql,
      end_sql: endSql,
    },
  },
];

